'use strict';
({params, imports}) => {
  const individual = params.entity;
  const moment = imports.moment;
  let eligibility = true;

  const condition11 = new imports.rulesConfig.RuleCondition({individual}).when.ageInYears.lessThanOrEqualTo(5).matches();

  const condition21 = new imports.rulesConfig.RuleCondition({individual}).when.gender.equals("Male").or.when.gender.equals("Female").matches();

  const malnutritionEnrollments = individual.enrolments
        .filter((enrl) => enrl && enrl.program && enrl.program.name == "Malnutrition Program" && enrl.voided == false && enrl.enrolmentDateTime && !enrl.programExitDateTime);

  if(malnutritionEnrollments.length > 0){
    eligibility = false;
  } else {
    eligibility = condition11 && condition21 ;
  }

  return eligibility;
};

'use strict';
({params, imports}) => {
    const individual = params.entity;
    const moment = imports.moment;
    const dateOfBirth = moment(individual.dateOfBirth).startOf('day');
    const today = moment().startOf('day');
    const age = today.diff(dateOfBirth, 'years', true);

    const isIndividualFemale = new imports.rulesConfig.RuleCondition({individual}).when.gender.equals("Female").matches();

    const isAgeEligible = age >= 12 && age <= 45;

    return isIndividualFemale && isAgeEligible;
};

'use strict';
({params, imports}) => {
  const individual = params.entity;
  const moment = imports.moment;
  let eligibility = true;

  const childEnrollments = individual.enrolments
        .filter((enrl) => enrl.program.name == "Child" && enrl.voided == false && enrl.enrolmentDateTime);

  let ageInMonths = individual.getAgeInMonths(); 
  if (ageInMonths < 6 || ageInMonths > 60) {
      eligibility = false; 
  }

  if (childEnrollments.length === 0) {
      eligibility = false;
  } else {
      const childEnrollment = childEnrollments[0];
      let gradationScreeningEnc = childEnrollment.getEncountersOfType('Child Gradation Screening');
      if(gradationScreeningEnc.length > 0){
          let malnutritionScreeningRequired = gradationScreeningEnc[0].getObservationReadableValue('e57e0d12-3ccb-4d21-a6a5-a76aeeec2647');
          if (ageInMonths < 6 || ageInMonths > 60) {
            eligibility = false; 
          } else {
            eligibility = (malnutritionScreeningRequired === 'Yes');
          }
      } else {
        eligibility = false;
      }
  }

  return eligibility;
};

