'use strict';
({params, imports}) => {
    const programEncounter = params.entity;
    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];
    const encounterType = programEncounter.encounterType.name;
    const currentEncounterDateTime = programEncounter.encounterDateTime;
    let filledANCTypes = []

    let ancEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, true);

    for (let i = 0; i < ancEncounters.length; i++){
        let enc =  ancEncounters[i];
        let ancCancelledStatus = enc.getObservationReadableValue("Do you want to cancel this ANC?");
        if(enc.encounterDateTime && enc.encounterDateTime < currentEncounterDateTime && ancCancelledStatus == 'No'){
            filledANCTypes.push(enc.getObservationReadableValue("ANC Type"));
        }
    }

    if(filledANCTypes.length > 0) {
        value = filledANCTypes.sort((a,b)=>{
            const numA = a.split(" ")[1];
            const numB = b.split(" ")[1];
            return numB - numA;
        }).join(", ");
    }
    else{
        value = "None";
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

'use strict';

({ params, imports }) => {
    const programEncounter = params.entity;
    const formElement = params.formElement;
    const _ = imports.lodash;

    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];

    const encounterType = programEncounter.encounterType.name;
    const currentEncounterDateTime = programEncounter.encounterDateTime;
    let filledAncTypes = [];

    // Define the order of ANC types
    const ancTypeOrder = [
        "5195f71e-63f5-44b3-a8ad-06ea617b9fa7", // ANC 1
        "75d9c2f4-b61c-493c-af29-8802353ef527", // ANC 2
        "1d016703-1639-4792-bac6-42d81778005b", // ANC 3
        "1173da26-de1b-43a3-9838-020d64fcbb95", // ANC 4
        "69f2a001-ae2a-4f90-b5ee-630a31940f91",
        "7ac8bf2e-b16a-4175-a267-af42759ec654",
        "035cdf96-4b17-4162-b54b-d94d1ab5c210",
        "4e6d7acc-693d-4ec7-9fc6-fbc1aef76d15",
        "42deef37-9902-49b9-b536-c59e321860c3"
    ];

    // Get previously filled ANC encounters
    let ancEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, true);

    for (let enc of ancEncounters) {
        if (enc.encounterDateTime && enc.encounterDateTime < currentEncounterDateTime) {
            const ancType = enc.getObservationValue("ANC Type");
            if (ancType) filledAncTypes.push(ancType);
        }
    }

    // Find the next available ANC type in the defined order
    const nextAncType = ancTypeOrder.find(type => !filledAncTypes.includes(type));
    value = nextAncType || null;

    // Skip all ANC types except the next one
    answersToSkip = ancTypeOrder
        .filter(type => type !== nextAncType) // Keep only the next ANC type
        .map(type => formElement.getAnswerWithConceptUuid(type))
        .filter(Boolean);

    return new imports.rulesConfig.FormElementStatus(
        formElement.uuid,
        visibility,
        value,
        answersToSkip,
        validationErrors
    );
};

