'use strict';
({params, imports}) => {
    const programEncounter = params.entity;
    const moment = imports.moment;
    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];
    let weightPercentile = null;

    const weight = programEncounter.getObservationValue('148fb61a-9d85-4876-b20f-50235c0d1d6e');

    let expectedWeight = null;
    if (weight) {
        const ageInYears = programEncounter.programEnrolment.individual.getAgeInYears(moment(programEncounter.encounterDateTime), true);
        const ageInMonths = programEncounter.programEnrolment.individual.getAgeInMonths(moment(programEncounter.encounterDateTime), true);

        if (ageInYears >= 1 && ageInYears <= 6) {
            expectedWeight = ageInYears * 2 + 8;
            expectedWeight = expectedWeight.toFixed(2);
        } else if (ageInYears < 1) { 
            expectedWeight = 0.5 * (ageInYears * 12) + 4;  
            expectedWeight = expectedWeight.toFixed(2);
        } else if (ageInYears > 6) {
            expectedWeight = ageInYears * 2 + 8;
            expectedWeight = expectedWeight.toFixed(2);
        }

        if (expectedWeight) {
            weightPercentile = (weight / expectedWeight) * 100;
            weightPercentile = weightPercentile.toFixed(2);
        }
    }

    if (weightPercentile) {
        if (weightPercentile > 80) {
            value = "Normal";
        } else if (weightPercentile > 70 && weightPercentile <= 80) {
            value = "Grade 1 Malnutrition";
        } else if (weightPercentile > 60 && weightPercentile <= 70) {
            value = "Grade 2 Malnutrition";
        } else if (weightPercentile > 50 && weightPercentile <= 60) {
            value = "Grade 3 Malnutrition";
        } else if (weightPercentile <= 50) {
            value = "Grade 4 Malnutrition";
        }
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

