    const encounterType = programEncounter.encounterType.name;
    const currentEncounterDateTime = programEncounter.encounterDateTime;
    let filledAncTypes = [];

    // Define the order of ANC types
    const ancTypeOrder = [
        "5195f71e-63f5-44b3-a8ad-06ea617b9fa7", // ANC 1
        "75d9c2f4-b61c-493c-af29-8802353ef527", // ANC 2
        "1d016703-1639-4792-bac6-42d81778005b", // ANC 3
        "1173da26-de1b-43a3-9838-020d64fcbb95", // ANC 4
