        "035cdf96-4b17-4162-b54b-d94d1ab5c210",
        "4e6d7acc-693d-4ec7-9fc6-fbc1aef76d15",
        "42deef37-9902-49b9-b536-c59e321860c3"
    ];

    // Get previously filled ANC encounters
    let ancEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, true);

    for (let enc of ancEncounters) {
        if (enc.encounterDateTime && enc.encounterDateTime < currentEncounterDateTime) {
            const ancType = enc.getObservationValue("ANC Type");
            if (ancType) filledAncTypes.push(ancType);
        }
    }

    // Find the next available ANC type in the defined order
    const nextAncType = ancTypeOrder.find(type => !filledAncTypes.includes(type));
    value = nextAncType || null;

    // Skip all ANC types except the next one
    answersToSkip = ancTypeOrder
        .filter(type => type !== nextAncType) // Keep only the next ANC type
        .map(type => formElement.getAnswerWithConceptUuid(type))
        .filter(Boolean);

    return new imports.rulesConfig.FormElementStatus(
        formElement.uuid,
        visibility,
        value,
        answersToSkip,
        validationErrors
    );
};

