'use strict';
({params, imports}) => {
    const programEncounter = params.entity;
    const moment = imports.moment;
    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];
    const encounterType = programEncounter.encounterType.name;
    const currentEncounterDateTime = programEncounter.encounterDateTime;
    let filledPncTypes = []

    let pncEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, true);

    for (let i = 0; i < pncEncounters.length; i++){
        let enc =  pncEncounters[i];
        let pncCancelledStatus = enc.getObservationReadableValue("bfc0a835-f5e9-42b3-8208-41d5e4df5761")
        if(enc.encounterDateTime && enc.encounterDateTime < currentEncounterDateTime && pncCancelledStatus == 'No'){
            filledPncTypes.push(enc.getObservationReadableValue("6877fa7e-d224-47ff-8213-54fb982afad6"))
        }
    }

    if(filledPncTypes.length) {
        filledPncTypes.sort((a, b) => {
            const numA = parseInt(a.match(/\d+$/)?.[0], 10) || 0;
            const numB = parseInt(b.match(/\d+$/)?.[0], 10) || 0;
            return numA - numB;
        });

        value = filledPncTypes.join(", ");
    }
    else{
        value = "None";
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

'use strict';

({ params, imports }) => {
    const programEncounter = params.entity;
    const formElement = params.formElement;
    const _ = imports.lodash;

    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];

    const encounterType = programEncounter.encounterType.name;
    const currentEncounterDateTime = programEncounter.encounterDateTime;
    let filledPncTypes = [];

    const pncTypeOrder = [
        "fd7a1973-cf3c-4c45-81dd-0f1508830ff3", 
        "52f8a5f2-dfd1-45f1-9437-d538c9da33bb", 
        "eb8996a4-ca34-4cd6-abfb-6d736d3b8cb6", 
        "18e6558f-a173-4a12-b97d-6da6f229e441", 
        "f50082bf-c45c-4c92-8def-40d56240ff16",
        "3b778d1d-2569-4909-a632-78806a8cbd90",
        "12506b3b-0569-4bc1-97ff-db9dbb5a8879"
    ];

    let pncEncounters = programEncounter.programEnrolment.getEncountersOfType(encounterType, true);

    for (let enc of pncEncounters) {
        if (enc.encounterDateTime && enc.encounterDateTime < currentEncounterDateTime) {
            const pncType = enc.getObservationValue("PNC Type");
            if (pncType) filledPncTypes.push(pncType);
        }
    }

    const nextPncType = pncTypeOrder.find(type => !filledPncTypes.includes(type));
    value = nextPncType || null;

    answersToSkip = pncTypeOrder
        .filter(type => type !== nextPncType) 
        .map(type => formElement.getAnswerWithConceptUuid(type))
        .filter(Boolean);

    return new imports.rulesConfig.FormElementStatus(
        formElement.uuid,
        visibility,
        value,
        answersToSkip,
        validationErrors
    );
};

