'use strict';
({params, imports}) => {
  const programEnrolment = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;

  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  function isInteger(value) {
    const number = parseFloat(value);
    return !isNaN(number) && Number.isInteger(number);
  }

  // Convert values to numbers
  const gravidaRaw = parseFloat(programEnrolment.getObservationReadableValue('Gravida'));
  const para = programEnrolment.getObservationReadableValue('Para');
  const miscarriages = programEnrolment.getObservationReadableValue('Miscarriages');
  const stillBirth = programEnrolment.getObservationReadableValue('Still births');

  if(!isNaN(gravidaRaw)) {
    if(!isInteger(gravidaRaw)) {
      validationErrors.push('Gravida cannot be a decimal value.');
    } else if (gravidaRaw > 1) {
      if(para !== null && para !== undefined && miscarriages !== null && miscarriages !== undefined && stillBirth !== null && stillBirth !== undefined) {
        const paraNum = parseFloat(para) || 0;
        const miscarriagesNum = parseFloat(miscarriages) || 0;
        const stillBirthNum = parseFloat(stillBirth) || 0;

        let additionOfOther = paraNum + miscarriagesNum + stillBirthNum + 1;

        if (additionOfOther !== gravidaRaw) {
          validationErrors.push("Gravida count should be the sum of Para, Miscarriages, and Still Birth + 1.");
        }
      }
    }
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

